Use ASP.NET Core's **`WebApplicationFactory<TEntryPoint>`** — it hosts your app in-memory and gives you an `HttpClient` that talks to it without opening a real port.

### 1. Add the test package

```bash
dotnet add tests/MyMcp.Tests.csproj package Microsoft.AspNetCore.Mvc.Testing
```

### 2. Write a test fixture

```csharp
using Microsoft.AspNetCore.Mvc.Testing;

public class McpTestFixture : WebApplicationFactory<Program>
{
    // Override ConfigureWebHost if you need to swap services:
    // protected override void ConfigureWebHost(IWebHostBuilder builder)
    // {
    //     builder.ConfigureServices(services => { /* mock deps */ });
    // }
}
```

### 3. Send MCP JSON-RPC requests over HTTP

MCP's Streamable HTTP transport uses `POST` with `Content-Type: application/json` and expects back either a single JSON-RPC response or an SSE stream. Example test:

```csharp
public class McpIntegrationTests : IClassFixture<McpTestFixture>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(McpTestFixture fixture)
    {
        _client = fixture.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsServerCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await PostJsonRpcAsync(request);

        Assert.Equal("2.0", response.GetProperty("jsonrpc").GetString());
        Assert.True(response.TryGetProperty("result", out var result));
        Assert.Equal("2025-03-26",
            result.GetProperty("protocolVersion").GetString());
    }

    [Fact]
    public async Task ToolsList_ReturnsRegisteredTools()
    {
        // Initialize first to establish session
        await PostJsonRpcAsync(MakeInitRequest(id: 1));

        var response = await PostJsonRpcAsync(new
        {
            jsonrpc = "2.0", id = 2,
            method = "tools/list", @params = new { }
        });

        var tools = response.GetProperty("result")
                            .GetProperty("tools");
        Assert.True(tools.GetArrayLength() > 0);
    }

    private async Task<JsonElement> PostJsonRpcAsync(object body)
    {
        var content = new StringContent(
            JsonSerializer.Serialize(body),
            Encoding.UTF8, "application/json");

        var httpResp = await _client.PostAsync("/mcp", content);
        httpResp.EnsureSuccessStatusCode();

        var ct = httpResp.Content.Headers.ContentType?.MediaType;
        if (ct == "application/json")
        {
            var doc = await JsonDocument.ParseAsync(
                await httpResp.Content.ReadAsStreamAsync());
            return doc.RootElement;
        }

        // SSE response — parse the first "data:" line
        var text = await httpResp.Content.ReadAsStringAsync();
        var dataLine = text.Split('\n')
            .First(l => l.StartsWith("data: "));
        return JsonDocument.Parse(dataLine[6..]).RootElement;
    }
}
```

### Key points

| Concept | Detail |
|---|---|
| **No real port** | `WebApplicationFactory` uses an in-memory `TestServer` |
| **Full pipeline** | Middleware, routing, DI — everything runs as in production |
| **SSE support** | Read the response stream and parse `data:` lines for SSE |
| **Session state** | If your server uses `Mcp-Session-Id`, capture it from the `initialize` response header and send it on subsequent requests |
| **Mock deps** | Override `ConfigureWebHost` to replace databases, APIs, etc. |

This gives you real HTTP-level integration tests against the full MCP protocol without any network I/O.
